const items = $input.all();
const now = new Date();
const results = [];

for (const item of items) {
  const attrs = item.json.attributes || {};
  const tags = item.json.tags || [];

  // Skip wenn schon no_show oder termin_wahrgenommen Tag
  if (tags.includes('no_show') || tags.includes('termin_wahrgenommen')) continue;
  if (!tags.includes('termin_gebucht')) continue;

  const dateParts = (attrs.TERMIN_DATUM || '').split('.');
  const time = (attrs.TERMIN_UHRZEIT || '10:00').split(':');

  if (dateParts.length !== 3) continue;

  const terminDate = new Date(
    parseInt(dateParts[2]), parseInt(dateParts[1]) - 1, parseInt(dateParts[0]),
    parseInt(time[0]), parseInt(time[1])
  );

  const hoursSince = (now - terminDate) / (1000 * 60 * 60);

  // No-Show: 24h nach Termin, kein 'termin_wahrgenommen' Tag
  if (hoursSince >= 24 && hoursSince <= 48) {
    results.push({ json: { ...item.json, hoursSinceTermin: Math.round(hoursSince) } });
  }
}

return results;
